VALUES
  ('social-worker-moex-06090', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作師為案主A釐定了「①改變對孩子的過度期待  ②修正案主的自動化思考  ③強化親子溝通能', '["增加案主自我控制」等的處遇目標，這位社會工作師採用了下列那一個理論的處遇目標？ 任務中心取向  心理暨社會學派  認知行為理論  精神分析學派", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06091', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '如果你/妳採用增強權能理論與弱勢案主工作，下列何者不是你/妳的工作取向的基本假設？ 與案主建立協同的夥伴關係 案主的問題源自於社會功能障礙 認為案主是一個有能力且有價值的人 案主問題源於無力感以致無法與環境交流、實現自己', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06092', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「人的成長與發展乃受到生物、心理和社會的三方面因素的交互影響」。這句話是下列那個理論的基礎？ 心理暨社會學派  社會支持網絡觀點  生態系統觀點  系統理論觀點', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06093', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於Reid（1983）所提的任務中心模式的社會工作原則，何者敘述錯誤？ 觀察學習  結構性的治療過程  問題聚焦與明確具體  短期解決問題', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06094', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在Bronfenbrenner（1979）的生態系統中，如果社會工作師評估案主的家庭生活對學校表現的影響，此時 社會工作師是在評估案主的那一個系統層次？ 微觀系統（microsystem）  外部系統（exosystem） 鉅視系統（macrosystem）  中介系統（mesosystem ）', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06095', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於敘事治療的描述，何者敘述錯誤？ 技術上強調去病理化，聚焦於微小改變  是後現代理論之一，重視意義詮釋和語言敘說 強調解構與問題外化    與案主平等的夥伴關係', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06096', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者與案主的專業關係是處遇成敗的重要關鍵，這種關係是從人文取向的基礎去看待人與人之間 的相處之道。因此，從人文取向的觀點來看，下列何者是社會工作專業的「靈魂」？ 技術與績效  信任與同理心  程序與法規  倫理守則與理論', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06097', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者的「紀錄撰寫不實」是屬於那一種業務過失？ 濫權（misfeasance）  瀆職（malfeasance）  怠職（nonfeasance）  抗拒（resistance）', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06098', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '許多國家的社會工作專業組織與國際社會工作專業組織，都制定社會工作專業倫理守則供社會工作者遵 守，並且成為社會工作界討論倫理議題的核心。請問社會工作專業倫理守則大都以那種倫理學的觀點為 基礎？ 義務論  直覺論  德行論  相對論', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06099', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有些社會福利組織要求社會工作者做不實的經費核銷，以及要求社會工作者薪水回捐，這些都是屬於組 織不符合倫理的情事。如果這些事件經常發生，那麼會發生這些不符合倫理的事件，最主要的原因是： 社會工作者太懦弱    組織文化偏差 組織倫理守則不夠完備   取得更多資源服務案主', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
